import {db} from "../db.js";

export function getFavorites(req, res) {
  const userId = req.user.id;
  const favorites = db.get("favorites").filter({ userId }).value();
  res.json(favorites);
}

export function addFavorite(req, res) {
  const userId = req.user.id;
  const { itemId } = req.body;
  const newFavorite = { id: Date.now().toString(), userId, itemId };
  db.get("favorites").push(newFavorite).write();
  res.status(201).json(newFavorite);
}

export function removeFavorite(req, res) {
  const userId = req.user.id;
  const { id } = req.params;
  const favorite = db.get("favorites").find({ id, userId }).value();
  if (!favorite) {
    return res.status(404).json({ message: "favorite not found" });
  }
  db.get("favorites").remove({ id, userId }).write();
  res.json({ message: "favorite removed" });
}

