import path from "path";
import { register, login } from "./controllers/auth.js";
import { searchAnime } from "./controllers/anime-search.js";
import express from "express";
import { TopAnime } from "./controllers/top-anime.js";
import { animeDetails } from "./controllers/anime-details.js";
import { cacheMiddleware } from "./middleware/cache.js";
import { getFavorites ,addFavorite,deleteFavorite } from "./controllers/favorites.js";
import { requireAuth } from "./middleware/auth.js";
export const router = express.Router();
router.get("/api/favorites", requireAuth, getFavorites);
  router.post("/api/favorites", requireAuth, addFavorite);
  router.delete("/api/favorites/:id", requireAuth, deleteFavorite);

router.get("/search/:entityType", (req, res) => {
  res.sendFile(path.join(import.meta.dirname, "..", "public", "search", "index.html"));
});

router.get("/:entityType/:id", (req, res) => {
  res.sendFile(path.join(import.meta.dirname, "..", "public", "entity", "index.html"));
});
router.post("/api/auth/register", register);
router.post("/api/auth/login", login);
  router.use(cacheMiddleware); // This line caches whats after only

router.get("/api/:entityType/top", TopAnime);
router.get("/api/:entityType/search", searchAnime);
router.get("/api/:entityType/:id", animeDetails);

import { db } from "../db.js";

  export function getFavorites(req, res) {
const username = req.user.username;
db.sql`SELECT * FROM favorites WHERE user_id = (SELECT id FROM users WHERE username = ${username})`
.then ((rows) => {
    res.json (rows);
})
.catch((err)=> {
    res.status(500).json ({message : "500 Internal Server Error"});

});
  }
  export function addFavorite(req, res) {
    const {entity_id, entity_type , title} = req.body;
    if (entity_type !== "anime" && entity_type !== "manga"){
return res.status(400).json({message : "entity_type must be anime or manga"});


}
if(!entity_id){
    return res.status(400).json ({message : "entity_id is required"});

    }
const username = req.user.username;
db.sql`INSERT INTO favorites (user_id, entity_id, entity_type, title)
VALUES ((SELECT id FROM users WHERE username = ${username}), ${entity_id}, ${entity_type},${title})
RETURNING *`
.then ((rows)=>{
    res.status(201).json(rows[0]);
})
.catch((err)=>{
    res.status(500).json({message : "500 Internal Server Error"});

});
  }

  export function deleteFavorite(req, res) {
const {id} = req.params;
const username = req.user.username;
db.sql`DELETE FROM favorites
WHERE id = ${id}
AND user_id = (SELECT id FROM users WHERE username = ${username})
RETURNING *`
.then((rows) => {
    if (rows.length === 0) {
      return res.status(404).json({ message: "favorite not found" });
    }
    res.status(200).json({ message: "favorite deleted" });
  })
  .catch((err) => {
    res.status(500).json({ message: "500 Internal Server Error" });
  });
  }

import jwt from "jsonwebtoken";

export function requireAuth(req, res, next) {
  const token = req.cookies.token;
  if (!token) {
    return res.status(401).json({ message: "unauthorized" });
  }
  try {
  const payload = jwt.verify(token, process.env.JWT_SECRET);
  req.user = payload;
  next();
} catch (err) {
  return res.status(401).json({ message: "unauthorized" });
}

}

